SELECT DISTINCT date, CAST(EXTRACT(year FROM date) AS INTEGER) AS year, CAST(EXTRACT(month FROM date) AS INTEGER) AS month, regiao_origem, regiao_destino, vendas_de_biodiesel FROM (SELECT make_date(TRY_CAST(split_part(trim("mes_ano"), '/', 2) AS INTEGER), TRY_CAST(split_part(trim("mes_ano"), '/', 1) AS INTEGER), 1) AS date, NULLIF(TRIM("regiao_origem"), '') AS regiao_origem, NULLIF(TRIM("regiao_destino"), '') AS regiao_destino, TRY_CAST(replace(replace(trim("vendas_de_biodiesel"), '.', ''), ',', '.') AS DOUBLE) AS vendas_de_biodiesel FROM "anp-brazil-vdpb-vendas-de-biodiesel-vendas-biodiesel-b100-m3") WHERE date IS NOT NULL AND (vendas_de_biodiesel IS NOT NULL)
